// TODO: Configure Google Ads OAuth2 credentials and customer IDs in n8n UI
// 
// Required setup:
// 1. Create Google Ads OAuth2 credentials in n8n
// 2. Set customer IDs for each brand:
//    - brand_id=1 (spa): customer ID TBD
//    - brand_id=2 (aesthetics): customer ID TBD  
//    - brand_id=3 (slimming): customer ID TBD
// 3. Set developer token in credentials
//
// Once configured, this node should emit one item per brand with:
//   { customer_id, brand_id, log_id, start_time }

const logResponse = $input.first().json;
const logId = Array.isArray(logResponse) ? logResponse[0].id : logResponse.id;
const startTime = $('Set Start Time').first().json.start_time;

const customers = [
  { customer_id: 'CUSTOMER_ID_SPA', brand_id: 1 },
  { customer_id: 'CUSTOMER_ID_AES', brand_id: 2 },
  { customer_id: 'CUSTOMER_ID_SLIM', brand_id: 3 }
];

return customers.map(c => ({ json: { ...c, log_id: logId, start_time: startTime } }));

const input = $input.first().json;
const brandId = $('Setup Customer IDs (TODO)').first().json.brand_id;

// Google Ads searchStream returns an array of result batches
const results = input.results || (Array.isArray(input) ? input.flatMap(b => b.results || []) : []);

// Aggregate by date
const byDate = {};
for (const row of results) {
  const date = row.segments?.date;
  if (!date) continue;

  if (!byDate[date]) {
    byDate[date] = { spend: 0, impressions: 0, clicks: 0, leads: 0, cpc_sum: 0, ctr_sum: 0, count: 0 };
  }

  // cost_micros needs to be divided by 1,000,000
  byDate[date].spend += (row.metrics?.costMicros || 0) / 1000000;
  byDate[date].impressions += parseInt(row.metrics?.impressions || 0, 10);
  byDate[date].clicks += parseInt(row.metrics?.clicks || 0, 10);
  byDate[date].leads += parseFloat(row.metrics?.conversions || 0);
  byDate[date].count++;
}

const rows = Object.entries(byDate).map(([date, d]) => {
  const cpl = d.leads > 0 ? Math.round((d.spend / d.leads) * 100) / 100 : null;
  const cpc = d.clicks > 0 ? Math.round((d.spend / d.clicks) * 100) / 100 : null;
  const ctr_pct = d.impressions > 0 ? Math.round((d.clicks / d.impressions) * 10000) / 100 : 0;

  return {
    date: date,
    brand_id: brandId,
    platform: 'google',
    spend: Math.round(d.spend * 100) / 100,
    impressions: d.impressions,
    clicks: d.clicks,
    leads: Math.round(d.leads),
    cpl: cpl,
    roas: null,
    ctr_pct: ctr_pct,
    cpc: cpc
  };
});

return rows.map(r => ({ json: r }));

const startTime = $('Set Start Time').first().json.start_time;
const logId = $('Setup Customer IDs (TODO)').first().json.log_id;
const totalRows = $input.all().length;
const durationSec = Math.round((Date.now() - startTime) / 1000);

return [{ json: {
  log_id: logId,
  status: 'success',
  rows_upserted: totalRows,
  duration_sec: durationSec
}}];
